dashboard.definition:
{
  "title": "Spines",
  "visualizations": {
    "viz_spines_0": {
      "type": "splunk.singlevalue",
      "dataSources": {
        "primary": "ds_spines_0"
      },
      "title": "NVE VNIs \u25b2 Up / \u25bc Down (Spines)",
      "description": "Single card showing the latest-snapshot count of operationally Up (\u25b2) and Down (\u25bc) NVE VNIs (cisco.vni-oper-state_info, nve-vni-oper) aggregated across every spine. Spines are BGP EVPN route-reflectors and normally host no NVE VNIs, so both counts usually read 0.",
      "options": {
        "sparklineDisplay": "off",
        "trendDisplay": "off"
      }
    },
    "viz_spines_1": {
      "type": "splunk.singlevalue",
      "dataSources": {
        "primary": "ds_spines_1"
      },
      "title": "BGP Sessions \u25b2 Up / \u25bc Down (Spines)",
      "description": "Single card showing the latest-snapshot count of BGP sessions that are Up (\u25b2, negotiated hold-time > 0) and Down (\u25bc, hold-time = 0) across every spine. A non-zero \u25bc Down count flags one or more BGP neighbors not Established.",
      "options": {
        "sparklineDisplay": "off",
        "trendDisplay": "off"
      }
    },
    "viz_spines_2": {
      "type": "splunk.singlevalue",
      "dataSources": {
        "primary": "ds_spines_2"
      },
      "title": "VTEP Tunnel Peers (Spines)",
      "options": {
        "sparklineDisplay": "off",
        "trendDisplay": "off"
      }
    },
    "viz_spines_3": {
      "type": "splunk.singlevalue",
      "dataSources": {
        "primary": "ds_spines_3"
      },
      "title": "Active L2 VNIs (Spines)",
      "options": {
        "sparklineDisplay": "off",
        "trendDisplay": "off"
      }
    },
    "viz_spines_4": {
      "type": "splunk.singlevalue",
      "dataSources": {
        "primary": "ds_spines_4"
      },
      "title": "Active VRFs / L3 VNIs (Spines)",
      "options": {
        "sparklineDisplay": "off",
        "trendDisplay": "off"
      }
    },
    "viz_spines_5": {
      "type": "splunk.singlevalue",
      "dataSources": {
        "primary": "ds_spines_5"
      },
      "title": "Silent Spines (>5m)",
      "options": {
        "sparklineDisplay": "off",
        "trendDisplay": "off",
        "backgroundColor": "> primary | seriesByIndex(0) | lastPoint() | rangeValue(singleValueColorConfig)"
      },
      "context": {
        "singleValueColorConfig": [
          {
            "to": 1,
            "value": "#53A051"
          },
          {
            "from": 1,
            "value": "#DC4E41"
          }
        ]
      }
    },
    "viz_spines_6": {
      "type": "splunk.line",
      "dataSources": {
        "primary": "ds_spines_6"
      },
      "title": "BGP Established Sessions per Spine",
      "options": {
        "legendDisplay": "right",
        "xAxisTitleVisibility": "hide",
        "yAxisTitleText": "Sessions",
        "nullValueDisplay": "connect"
      }
    },
    "viz_spines_7": {
      "type": "splunk.line",
      "dataSources": {
        "primary": "ds_spines_7"
      },
      "title": "L3 VNI Count per Spine",
      "options": {
        "legendDisplay": "right",
        "xAxisTitleVisibility": "hide",
        "yAxisTitleText": "VNI Count",
        "nullValueDisplay": "connect"
      }
    },
    "viz_spines_8": {
      "type": "splunk.line",
      "dataSources": {
        "primary": "ds_spines_8"
      },
      "title": "L3 VNI (VRF) Count per Spine",
      "options": {
        "legendDisplay": "right",
        "xAxisTitleVisibility": "hide",
        "yAxisTitleText": "VRF Count",
        "nullValueDisplay": "connect"
      }
    },
    "viz_spines_9": {
      "type": "splunk.table",
      "dataSources": {
        "primary": "ds_spines_9"
      },
      "title": "BGP Session State",
      "options": {
        "columnFormat": {
          "session_state": {
            "color": "> table | seriesByName(\"session_state\") | matchValue(sessionstateColorConfig)"
          }
        }
      },
      "context": {
        "sessionstateColorConfig": [
          {
            "match": "ESTABLISHED",
            "value": "#53A051"
          },
          {
            "match": "DOWN",
            "value": "#DC4E41"
          },
          {
            "match": "IDLE",
            "value": "#DC4E41"
          },
          {
            "match": "ACTIVE",
            "value": "#F8BE34"
          },
          {
            "match": "CONNECT",
            "value": "#F8BE34"
          }
        ]
      }
    },
    "viz_spines_10": {
      "type": "splunk.table",
      "dataSources": {
        "primary": "ds_spines_10"
      },
      "title": "BGP EVPN Peering Detail",
      "options": {
        "columnFormat": {
          "session_state": {
            "color": "> table | seriesByName(\"session_state\") | matchValue(sessionstateColorConfig)"
          }
        }
      },
      "context": {
        "sessionstateColorConfig": [
          {
            "match": "ESTABLISHED",
            "value": "#53A051"
          },
          {
            "match": "DOWN",
            "value": "#DC4E41"
          }
        ]
      }
    },
    "viz_spines_11": {
      "type": "splunk.table",
      "dataSources": {
        "primary": "ds_spines_11"
      },
      "title": "NVE Interface Global State"
    },
    "viz_spines_12": {
      "type": "splunk.table",
      "dataSources": {
        "primary": "ds_spines_12"
      },
      "title": "NVE Peer Adjacency",
      "description": "Peer count is authoritative (keyed on peer-addr). The eVNI column derives from nve-peer-oper/cp-vnis, a leaf-list DEPRECATED in IOS-XE 17.18 \u2014 for a peer carrying multiple eVNIs only one value is shown. Migrate to nve-peer-oper/peer-vni-group/vni once the device build streams it."
    },
    "viz_spines_13": {
      "type": "splunk.sankey",
      "dataSources": {
        "primary": "ds_spines_13"
      },
      "title": "BGP VRF Prefix Distribution: Hostname \u2192 VRF \u2192 Address Family (Total Prefixes)",
      "options": {
        "seriesColors": [
          "#1D6FA4",
          "#53A051",
          "#F8BE34",
          "#DC4E41",
          "#F1813F",
          "#6DB7C6"
        ]
      }
    },
    "viz_spines_14": {
      "type": "splunk.table",
      "dataSources": {
        "primary": "ds_spines_14"
      },
      "title": "NVE VNI Table"
    },
    "viz_spines_15": {
      "type": "splunk.line",
      "dataSources": {
        "primary": "ds_spines_15"
      },
      "title": "NVE Peers Over Time \u2014 Per Spine",
      "options": {
        "legendDisplay": "right",
        "xAxisTitleVisibility": "hide",
        "yAxisTitleText": "VTEP Peers",
        "nullValueDisplay": "connect"
      }
    },
    "viz_spines_16": {
      "type": "splunk.table",
      "dataSources": {
        "primary": "ds_spines_16"
      },
      "title": "Per-VNI Peer Reachability Matrix per Spine \u2014 VNI \u00d7 Remote VTEP (1 = learned, 0 = gap)",
      "description": "Control-plane reachability of each VXLAN segment from the per-VNI / per-peer router-MAC table (nve-peer-oper/peer-vni-group), now sliceable because the fixed yanggrpcreceiver carries the numeric vni list key and the peer-addr key as dimensions. Each row is one spine's VNI (typically only the L3 transit VNI a route-reflector spine participates in); each column is a remote VTEP (peer loopback resolved to a hostname); a cell = 1 when that spine has learned the VNI's router-MAC from that peer, 0 when it has not \u2014 a per-segment cross-check that was impossible while numeric keys were dropped."
    }
  },
  "dataSources": {
    "ds_spines_input0": {
      "type": "ds.search",
      "options": {
        "query": "| inputlookup evpn_device_inventory | stats count by site | fields site | sort site",
        "queryParameters": {
          "earliest": "0",
          "latest": "now"
        }
      },
      "name": "Site"
    },
    "ds_spines_0": {
      "type": "ds.search",
      "options": {
        "query": "| mstats latest(\"cisco.vni-oper-state_info\") AS _m WHERE `evpn_index` earliest=$timeRange.earliest$ span=1m \"cisco.encoding_path\"=\"Cisco-IOS-XE-nve-oper:nve-oper-data/nve-oper/nve-vni-oper\" BY \"cisco.node_id\", \"vni-id\", \"value\" | `evpn_lookup` | where site=\"$site$\" AND role=\"spine\" | sort 0 - _time | dedup hostname, \"vni-id\" | eval down=if(value=\"nve-vni-state-down\",1,0) | stats sum(down) AS Down count AS Total | eval Up=Total-Down | eval vni_state=\"\u25b2 \".Up.\"   \u25bc \".Down | fields vni_state",
        "queryParameters": {
          "earliest": "$timeRange.earliest$",
          "latest": "now"
        }
      },
      "name": "NVE VNIs \u25b2 Up / \u25bc Down (Spines)"
    },
    "ds_spines_1": {
      "type": "ds.search",
      "options": {
        "query": "| mstats latest(\"cisco.negotiated-keepalive-timers.hold-time\") AS hold_time WHERE `evpn_index` earliest=$timeRange.earliest$ \"cisco.encoding_path\"=\"Cisco-IOS-XE-bgp-oper:bgp-state-data/neighbors/neighbor\" BY \"cisco.node_id\", \"vrf-name\", \"neighbor-id\" | `evpn_lookup` | where site=\"$site$\" AND role=\"spine\" | stats count(eval(hold_time>0)) AS Up count(eval(hold_time==0)) AS Down | eval bgp_state=\"\u25b2 \".Up.\"   \u25bc \".Down | fields bgp_state",
        "queryParameters": {
          "earliest": "$timeRange.earliest$",
          "latest": "now"
        }
      },
      "name": "BGP Sessions \u25b2 Up / \u25bc Down (Spines)"
    },
    "ds_spines_2": {
      "type": "ds.search",
      "options": {
        "query": "| mstats latest(\"cisco.cp-vnis.\") AS cp_vnis WHERE `evpn_index` earliest=$timeRange.earliest$ \"cisco.encoding_path\"=\"Cisco-IOS-XE-nve-oper:nve-oper-data/nve-oper/nve-peer-oper\" BY \"cisco.node_id\", \"peer-addr\" | rename \"peer-addr\" AS peer_addr | `evpn_lookup` | where site=\"$site$\" AND role=\"spine\" | stats dc(peer_addr) AS peers BY hostname | stats sum(peers) AS n | fields n",
        "queryParameters": {
          "earliest": "$timeRange.earliest$",
          "latest": "now"
        }
      },
      "name": "VTEP Tunnel Peers (Spines)"
    },
    "ds_spines_3": {
      "type": "ds.search",
      "options": {
        "query": "| mstats latest(\"cisco.vni-type_info\") AS x WHERE `evpn_index` earliest=$timeRange.earliest$ \"cisco.encoding_path\"=\"Cisco-IOS-XE-nve-oper:nve-oper-data/nve-oper/nve-vni-oper\" BY \"cisco.node_id\", \"vni-id\", \"value\" | `evpn_lookup` | where site=\"$site$\" AND role=\"spine\" AND value=\"nve-vni-type-l2\" | stats dc(\"vni-id\") AS n | fields n",
        "queryParameters": {
          "earliest": "$timeRange.earliest$",
          "latest": "now"
        }
      },
      "name": "Active L2 VNIs (Spines)"
    },
    "ds_spines_4": {
      "type": "ds.search",
      "options": {
        "query": "| mstats latest(\"cisco.vni-type_info\") AS x WHERE `evpn_index` earliest=$timeRange.earliest$ \"cisco.encoding_path\"=\"Cisco-IOS-XE-nve-oper:nve-oper-data/nve-oper/nve-vni-oper\" BY \"cisco.node_id\", \"vni-id\", \"value\" | `evpn_lookup` | where site=\"$site$\" AND role=\"spine\" AND value=\"nve-vni-type-l3\" | stats dc(\"vni-id\") AS n | fields n",
        "queryParameters": {
          "earliest": "$timeRange.earliest$",
          "latest": "now"
        }
      },
      "name": "Active VRFs / L3 VNIs (Spines)"
    },
    "ds_spines_5": {
      "type": "ds.search",
      "options": {
        "query": "| mstats latest(\"cisco.negotiated-keepalive-timers.hold-time\") AS val WHERE `evpn_index` earliest=$timeRange.earliest$ BY \"cisco.node_id\" | `evpn_lookup` | where site=\"$site$\" AND role=\"spine\" | where _time < (now()-300) | stats count AS n",
        "queryParameters": {
          "earliest": "$timeRange.earliest$",
          "latest": "now"
        }
      },
      "name": "Silent Spines (>5m)"
    },
    "ds_spines_6": {
      "type": "ds.search",
      "options": {
        "query": "| mstats latest(\"cisco.negotiated-keepalive-timers.hold-time\") AS hold_time WHERE `evpn_index` earliest=$timeRange.earliest$ span=30s BY \"cisco.node_id\", \"vrf-name\", \"neighbor-id\" | `evpn_lookup` | where site=\"$site$\" AND role=\"spine\" | eval established=if(hold_time>0, 1, 0) | stats sum(established) AS established by _time, hostname | xyseries _time hostname established | sort _time",
        "queryParameters": {
          "earliest": "$timeRange.earliest$",
          "latest": "$timeRange.latest$"
        }
      },
      "name": "BGP Established Sessions per Spine"
    },
    "ds_spines_7": {
      "type": "ds.search",
      "options": {
        "query": "| mstats latest(\"cisco.l3cp-vni-num\") AS l3_vni_count WHERE `evpn_index` earliest=$timeRange.earliest$ span=5m \"cisco.encoding_path\"=\"Cisco-IOS-XE-nve-oper:nve-oper-data/nve-oper\" BY \"cisco.node_id\" | `evpn_lookup` | where site=\"$site$\" AND role=\"spine\" | stats last(l3_vni_count) AS l3_vni_count by _time, hostname | xyseries _time hostname l3_vni_count | sort _time",
        "queryParameters": {
          "earliest": "$timeRange.earliest$",
          "latest": "$timeRange.latest$"
        }
      },
      "name": "L3 VNI Count per Spine"
    },
    "ds_spines_8": {
      "type": "ds.search",
      "options": {
        "query": "| mstats latest(\"cisco.l3cp-vni-num\") AS l3vni WHERE `evpn_index` earliest=$timeRange.earliest$ span=5m \"cisco.encoding_path\"=\"Cisco-IOS-XE-nve-oper:nve-oper-data/nve-oper\" BY \"cisco.node_id\" | `evpn_lookup` | where site=\"$site$\" AND role=\"spine\" | stats last(l3vni) AS l3vni by _time, hostname | xyseries _time hostname l3vni | sort _time",
        "queryParameters": {
          "earliest": "$timeRange.earliest$",
          "latest": "$timeRange.latest$"
        }
      },
      "name": "L3 VNI (VRF) Count per Spine"
    },
    "ds_spines_9": {
      "type": "ds.search",
      "options": {
        "query": "| mstats latest(\"cisco.negotiated-keepalive-timers.hold-time\") AS hold_time WHERE `evpn_index` earliest=$timeRange.earliest$ \"cisco.encoding_path\"=\"Cisco-IOS-XE-bgp-oper:bgp-state-data/neighbors/neighbor\" BY \"cisco.node_id\", \"vrf-name\", \"neighbor-id\" | rename \"vrf-name\" AS vrf_name, \"neighbor-id\" AS neighbor_id | `evpn_lookup` | where site=\"$site$\" AND role=\"spine\" | lookup evpn_device_inventory loopback AS neighbor_id OUTPUT hostname AS neighbor_hostname | eval neighbor_hostname=coalesce(neighbor_hostname, neighbor_id) | eval session_state=if(hold_time>0,\"ESTABLISHED\",\"DOWN\") | table hostname, ip_address, neighbor_hostname, vrf_name, session_state | sort hostname",
        "queryParameters": {
          "earliest": "$timeRange.earliest$",
          "latest": "$timeRange.latest$"
        }
      },
      "name": "BGP Session State"
    },
    "ds_spines_10": {
      "type": "ds.search",
      "options": {
        "query": "| mstats latest(\"cisco.as\") AS remote_as latest(\"cisco.bgp-neighbor-counters.received.updates\") AS msg_rcvd latest(\"cisco.bgp-neighbor-counters.sent.updates\") AS msg_sent latest(\"cisco.negotiated-keepalive-timers.hold-time\") AS hold_time WHERE `evpn_index` earliest=$timeRange.earliest$ \"cisco.encoding_path\"=\"Cisco-IOS-XE-bgp-oper:bgp-state-data/neighbors/neighbor\" BY \"cisco.node_id\", \"vrf-name\", \"neighbor-id\" | rename \"vrf-name\" AS vrf_name, \"neighbor-id\" AS neighbor_id | `evpn_lookup` | where site=\"$site$\" AND role=\"spine\" | lookup evpn_device_inventory loopback AS neighbor_id OUTPUT hostname AS peer_hostname | eval peer_hostname=coalesce(peer_hostname, neighbor_id) | eval session_state=if(hold_time>0,\"ESTABLISHED\",\"DOWN\") | eval remote_as=tostring(round(remote_as,0)) | table hostname, ip_address, peer_hostname, remote_as, vrf_name, session_state, msg_rcvd, msg_sent | sort hostname, peer_hostname",
        "queryParameters": {
          "earliest": "$timeRange.earliest$",
          "latest": "$timeRange.latest$"
        }
      },
      "name": "BGP EVPN Peering Detail"
    },
    "ds_spines_11": {
      "type": "ds.search",
      "options": {
        "query": "| mstats latest(\"cisco.l2cp-vni-num\") AS l2cp latest(\"cisco.l3cp-vni-num\") AS l3cp latest(\"cisco.l2dp-vni-num\") AS l2dp latest(\"cisco.is-bgp-signal\") AS bgp_signal latest(\"cisco.vxlan-port\") AS vxlan_port WHERE `evpn_index` earliest=$timeRange.earliest$ \"cisco.encoding_path\"=\"Cisco-IOS-XE-nve-oper:nve-oper-data/nve-oper\" BY \"cisco.node_id\" | `evpn_lookup` | where site=\"$site$\" AND role=\"spine\" | table hostname, ip_address, l2cp, l3cp, l2dp, bgp_signal, vxlan_port | sort hostname",
        "queryParameters": {
          "earliest": "$timeRange.earliest$",
          "latest": "$timeRange.latest$"
        }
      },
      "name": "NVE Interface Global State"
    },
    "ds_spines_12": {
      "type": "ds.search",
      "options": {
        "query": "| mstats latest(\"cisco.cp-vnis.\") AS cp_vnis WHERE `evpn_index` earliest=$timeRange.earliest$ \"cisco.encoding_path\"=\"Cisco-IOS-XE-nve-oper:nve-oper-data/nve-oper/nve-peer-oper\" BY \"cisco.node_id\", \"peer-addr\" | rename \"peer-addr\" AS peer_addr | `evpn_lookup` | where site=\"$site$\" AND role=\"spine\" | eval cp_vnis=round(cp_vnis,0) | rename cp_vnis AS \"eVNI (1 of N)\" | table hostname, ip_address, peer_addr, \"eVNI (1 of N)\" | sort hostname, peer_addr",
        "queryParameters": {
          "earliest": "$timeRange.earliest$",
          "latest": "now"
        }
      },
      "name": "NVE Peer Adjacency"
    },
    "ds_spines_13": {
      "type": "ds.search",
      "options": {
        "query": "| mstats latest(\"cisco.prefixes.total-entries\") AS total_prefixes WHERE `evpn_index` earliest=$timeRange.earliest$ BY \"cisco.node_id\", \"vrf-name\", \"afi-safi\" | rename \"vrf-name\" AS vrf_name, \"afi-safi\" AS afi_safi | `evpn_lookup` | where site=\"$site$\" AND role=\"spine\" | where afi_safi IN (\"l2vpn-e-vpn\",\"ipv4-unicast\",\"vpnv4-unicast\",\"ipv6-unicast\") | eval total_prefixes=if(total_prefixes=0,1,total_prefixes) | eval device=hostname | eval pairs=mvappend(device.\"|||\".vrf_name, vrf_name.\"|||\".afi_safi) | mvexpand pairs | eval from=mvindex(split(pairs,\"|||\"),0), to=mvindex(split(pairs,\"|||\"),1) | stats sum(total_prefixes) AS value BY from, to",
        "queryParameters": {
          "earliest": "$timeRange.earliest$",
          "latest": "$timeRange.latest$"
        }
      },
      "name": "BGP VRF Prefix Distribution: Hostname \u2192 VRF \u2192 Address Family (Total Prefixes)"
    },
    "ds_spines_14": {
      "type": "ds.search",
      "options": {
        "query": "| mstats latest(\"cisco.l3-vni-id\") AS l3_vni_id latest(\"cisco.svi-vlan-id\") AS svi_vlan latest(\"cisco.local-routing\") AS local_routing latest(\"cisco.vlan-id\") AS vlan_id WHERE `evpn_index` earliest=$timeRange.earliest$ \"cisco.encoding_path\"=\"Cisco-IOS-XE-nve-oper:nve-oper-data/nve-oper/nve-vni-oper\" BY \"cisco.node_id\", \"vni-id\" | append [ mstats latest(\"cisco.vni-type_info\") AS _x WHERE `evpn_index` earliest=$timeRange.earliest$ \"cisco.encoding_path\"=\"Cisco-IOS-XE-nve-oper:nve-oper-data/nve-oper/nve-vni-oper\" BY \"cisco.node_id\", \"vni-id\", \"value\" | eval vni_type=value | fields \"cisco.node_id\", \"vni-id\", vni_type ] | append [ mstats latest(\"cisco.nve-vni-vrf_info\") AS _x WHERE `evpn_index` earliest=$timeRange.earliest$ \"cisco.encoding_path\"=\"Cisco-IOS-XE-nve-oper:nve-oper-data/nve-oper/nve-vni-oper\" BY \"cisco.node_id\", \"vni-id\", \"value\" | eval vrf=value | fields \"cisco.node_id\", \"vni-id\", vrf ] | append [ mstats latest(\"cisco.vni-oper-state_info\") AS _x WHERE `evpn_index` earliest=$timeRange.earliest$ \"cisco.encoding_path\"=\"Cisco-IOS-XE-nve-oper:nve-oper-data/nve-oper/nve-vni-oper\" BY \"cisco.node_id\", \"vni-id\", \"value\" | eval oper_state=value | fields \"cisco.node_id\", \"vni-id\", oper_state ] | stats values(l3_vni_id) AS l3_vni_id values(svi_vlan) AS svi_vlan values(local_routing) AS local_routing values(vlan_id) AS vlan_id values(vni_type) AS vni_type values(vrf) AS vrf values(oper_state) AS oper_state BY \"cisco.node_id\", \"vni-id\" | `evpn_lookup` | where site=\"$site$\" AND role=\"spine\" | eval VNI=if(vni_type=\"nve-vni-type-l2\", svi_vlan, vlan_id), \"Oper State\"=case(oper_state=\"nve-vni-state-up\", \"Up\", oper_state=\"nve-vni-state-down\", \"Down\", true(), oper_state) | rename \"vni-id\" AS \"VNI ID\" | table hostname, \"VNI ID\", vni_type, vrf, \"Oper State\", VNI, l3_vni_id, svi_vlan, local_routing | sort hostname, vni_type, vrf",
        "queryParameters": {
          "earliest": "$timeRange.earliest$",
          "latest": "$timeRange.latest$"
        }
      },
      "name": "NVE VNI Table"
    },
    "ds_spines_15": {
      "type": "ds.search",
      "options": {
        "query": "| mstats count(\"cisco.cp-vnis.\") AS cp_vnis WHERE `evpn_index` earliest=$timeRange.earliest$ span=5m \"cisco.encoding_path\"=\"Cisco-IOS-XE-nve-oper:nve-oper-data/nve-oper/nve-peer-oper\" BY \"cisco.node_id\", \"peer-addr\" | rename \"peer-addr\" AS peer_addr | `evpn_lookup` | where site=\"$site$\" AND role=\"spine\" | stats dc(peer_addr) AS nve_peers by _time, hostname | xyseries _time hostname nve_peers | sort _time",
        "queryParameters": {
          "earliest": "$timeRange.earliest$",
          "latest": "$timeRange.latest$"
        }
      },
      "name": "NVE Peers Over Time \u2014 Per Spine"
    },
    "ds_spines_16": {
      "type": "ds.search",
      "options": {
        "query": "| mstats latest(\"cisco.rmac_info\") AS present WHERE `evpn_index` earliest=$timeRange.earliest$ \"cisco.encoding_path\"=\"Cisco-IOS-XE-nve-oper:nve-oper-data/nve-oper/nve-peer-oper/peer-vni-group\" BY \"cisco.node_id\", \"vni\", \"peer-addr\" | `evpn_lookup` | where site=\"$site$\" AND role=\"spine\" | lookup evpn_device_inventory loopback AS \"peer-addr\" OUTPUT hostname AS peer_name | eval peer_name=coalesce(peer_name, 'peer-addr'), row=hostname.\" \u00b7 VNI \".'vni', present=1 | xyseries row peer_name present | fillnull value=0 | sort row",
        "queryParameters": {
          "earliest": "$timeRange.earliest$",
          "latest": "now"
        }
      },
      "name": "Per-VNI Peer Reachability Matrix per Spine \u2014 VNI \u00d7 Remote VTEP (1 = learned, 0 = gap)"
    }
